mapper.select:
SELECT q.employee_id AS employeeId, AVG(q.t_score) AS averageTScore, AVG(q.uph_score) AS averageProductivityScore, AVG(q.yield_score) AS averageQualityScore, AVG(q.lead_time_score) AS averageEquipmentResponseScore FROM quantitative_evaluation q WHERE q.eval_period_id = #{evaluationPeriodId} AND q.status IN
#{status}
AND q.t_score IS NOT NULL GROUP BY q.employee_id ORDER BY q.employee_id
